// Master TypeScript Interfaces for POLLN-RTT Round 5

import type {
  ConditionalGeometrySchema,
  GeometricSpace,
  ProbabilityDistribution,
  ConditionSet,
  Transformation,
  MontyHallFoldOperation
} from './conditional_geometry_schema';

import type {
  FoldableTensorSchema,
  FoldableTensor,
  FlattenedRepresentation,
  CreasePattern,
  PermutationGroup,
  AssemblyKey
} from './foldable_tensor_schema';

import type {
  ChannelDepthSchema,
  ChannelDepth,
  CognitiveCost,
  DepthCostAnalysis
} from './channel_depth_schema';

import type {
  FoldingGroupSchema,
  FoldingGroup,
  FoldingGroupElement,
  FoldOperation
} from './folding_group_schema';

// Schema Reference
export interface SchemaReference {
  schemaId: string;
  version: string;
  type: string;
}

// Framework Containers
export interface ConditionalGeometryFramework {
  schemaRef?: SchemaReference;
  geometricSpace?: GeometricSpace;
  probabilityDistribution?: ProbabilityDistribution;
  conditions?: ConditionSet;
  transformation?: Transformation;
  montyHallFold?: MontyHallFoldOperation;
}

export interface FoldableTensorFramework {
  schemaRef?: SchemaReference;
  flattenedRepresentation?: FlattenedRepresentation;
  creasePattern?: CreasePattern;
  permutationGroup?: PermutationGroup;
  assemblyKey?: AssemblyKey;
}

export interface ChannelDepthFramework {
  schemaRef?: SchemaReference;
  channelDepth?: ChannelDepth;
  cognitiveCost?: CognitiveCost;
}

export interface FoldingGroupFramework {
  schemaRef?: SchemaReference;
  groupStructure?: FoldingGroup;
  elements?: FoldingGroupElement[];
  operations?: FoldOperation[];
}

// Integration Layer
export interface Integration {
  conditionalGeometryToFoldableTensor?: {
    coordinateEmbedding?: string;
    probabilityWeighting?: string;
    constraintProjection?: string;
  };
  foldableTensorToFoldingGroup?: {
    creaseToPermutation?: string;
    foldToZ2Tuple?: string;
    assemblyVerification?: string;
  };
  channelDepthToCognitiveCost?: {
    visitAccumulation?: string;
    decayIntegration?: string;
    costScaling?: string;
  };
  globalConstraints?: {
    conservationLaws?: string[];
    symmetryRequirements?: string[];
  };
}

// Computation Graph
export interface ComputationGraph {
  nodes: Array<{
    id: string;
    type: string;
    framework: string;
    operation: string;
  }>;
  edges: Array<{
    source: string;
    target: string;
    dataType: string;
  }>;
  executionOrder: string[];
}

// Validation
export interface ValidationResult {
  isValid: boolean;
  errors: Array<{
    path: string;
    message: string;
    severity: 'error' | 'warning' | 'info';
  }>;
}

// Master Schema
export interface MasterSchema {
  schemaVersion: string;
  id: string;
  timestamp?: string;
  componentSchemas: {
    conditionalGeometry?: SchemaReference;
    foldableTensor?: SchemaReference;
    channelDepth?: SchemaReference;
    foldingGroup?: SchemaReference;
  };
  conditionalGeometry?: ConditionalGeometryFramework;
  foldableTensor?: FoldableTensorFramework;
  channelDepth?: ChannelDepthFramework;
  foldingGroup?: FoldingGroupFramework;
  integration?: Integration;
  computationGraph?: ComputationGraph;
  validation?: ValidationResult;
  metadata?: {
    project?: string;
    author?: string;
    description?: string;
    tags?: string[];
  };
}

// Type guards
export function isConditionalGeometryValid(data: unknown): data is ConditionalGeometrySchema {
  return typeof data === 'object' && data !== null && 'geometricSpace' in data;
}

export function isFoldableTensorValid(data: unknown): data is FoldableTensorSchema {
  return typeof data === 'object' && data !== null && 'foldableTensor' in data;
}

export function isChannelDepthValid(data: unknown): data is ChannelDepthSchema {
  return typeof data === 'object' && data !== null && 'channelDepth' in data;
}

export function isFoldingGroupValid(data: unknown): data is FoldingGroupSchema {
  return typeof data === 'object' && data !== null && 'foldingGroup' in data;
}
